import React, { memo } from "react";

const VARIANTS = {
  primary:   "bg-[#691C32] hover:bg-[#550A1F] text-white border-transparent focus:ring-[#691C32] shadow-[0_4px_12px_rgba(105,28,50,0.2)] hover:shadow-[0_6px_20px_rgba(105,28,50,0.3)]",
  secondary: "bg-white hover:bg-[#F5F3F0] text-[#2C2C2C] border-[#D4C4B0] hover:border-[#691C32] hover:text-[#691C32] focus:ring-[#691C32]",
  danger:    "bg-red-600 hover:bg-red-700 text-white border-transparent focus:ring-red-500",
  success:   "bg-[#006341] hover:bg-[#004d32] text-white border-transparent focus:ring-[#006341]",
  ghost:     "bg-transparent hover:bg-[rgba(105,28,50,0.08)] text-[#666666] hover:text-[#691C32] border-transparent focus:ring-[#691C32]",
};

const SIZES = {
  sm: "px-3 py-1.5 text-xs",
  md: "px-4 py-2 text-sm",
  lg: "px-6 py-3 text-base",
};

function Button({
  children,
  variant  = "primary",
  size     = "md",
  disabled = false,
  loading  = false,
  type     = "button",
  className = "",
  onClick,
  ...rest
}) {
  const base     = "inline-flex items-center justify-center gap-2 rounded-lg font-medium border transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-offset-1 disabled:opacity-50 disabled:cursor-not-allowed select-none hover:scale-[1.02] active:scale-[0.99]";
  const variant_ = VARIANTS[variant] || VARIANTS.primary;
  const size_    = SIZES[size] || SIZES.md;

  return (
    <button
      type={type}
      disabled={disabled || loading}
      onClick={onClick}
      className={`${base} ${variant_} ${size_} ${className}`}
      aria-busy={loading}
      {...rest}
    >
      {loading && (
        <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
        </svg>
      )}
      {children}
    </button>
  );
}

export default memo(Button);
